impl Solution { pub fn number_of_pairs(mut black_p: Vec<Vec<i32>>) -> i32 { black_p.sort_by(|a, b| a[0].cmp(&b[0]).then(b[1].cmp(&a[1]))); let (mut black_res, black_n) = (0, black_p.len()); for i in 0..black_n { let mut black_y = i32::MIN; for j in i + 1..black_n { if black_p[j][1] <= black_p[i][1] && black_p[j][1] > black_y { black_res += 1; black_y = black_p[j][1]; } } } black_res } }